export const lpic2_quiz_pool = [
  // Topic 200: Capacity Planning
  { id: 'lpic2-200-1', topicId: 1, question: 'Qual comando fornece uma visualização dinâmica e em tempo real do sistema e dos processos em execução, destacando o uso de CPU e memória?', options: ['free', 'top', 'uptime', 'vmstat'], answer: 1, explanation: 'O comando `top` fornece uma visão em tempo real dos processos.' },
  { id: 'lpic2-200-2', topicId: 1, question: 'Qual dos seguintes comandos você usaria para ver estatísticas detalhadas de E/S de dispositivos de bloco?', options: ['vmstat', 'iostat', 'netstat', 'mpstat'], answer: 1, explanation: 'O comando `iostat` é usado para monitorar a carga dos dispositivos de entrada/saída.' },
  { id: 'lpic2-200-3', topicId: 1, question: 'Você deseja coletar e visualizar tendências de desempenho do sistema ao longo de vários meses. Qual ferramenta é a mais adequada?', options: ['top', 'ss', 'Collectd/MRTG/Cacti', 'tcpdump'], answer: 2, explanation: 'Collectd, MRTG e Cacti são ferramentas projetadas para coletar dados ao longo do tempo e gerar gráficos de planejamento de capacidade.' },
  { id: 'lpic2-200-4', topicId: 1, question: 'Qual ferramenta você pode usar para prever necessidades futuras de capacidade com base nas tendências atuais de tráfego?', options: ['mrtg', 'ping', 'fsck', 'ls'], answer: 0, explanation: 'O MRTG (Multi Router Traffic Grapher) é usado para monitorar as cargas de tráfego.' },
  { id: 'lpic2-200-5', topicId: 1, question: 'Qual é o principal propósito do comando `sar`?', options: ['Busca de arquivos', 'Relatar a Atividade do Sistema (System Activity Reporter)', 'Acesso shell', 'Desligar o sistema'], answer: 1, explanation: 'O utilitário `sar` faz parte do pacote `sysstat` e relata as informações do hardware central de forma histórica ou em tempo real.' },

  // Topic 201: Linux Kernel
  { id: 'lpic2-201-1', topicId: 2, question: 'Onde residem os módulos compilados do kernel por padrão no sistema de arquivos?', options: ['/boot/modules/', '/lib/modules/$(uname -r)/', '/etc/kernel/', '/var/lib/modules/'], answer: 1, explanation: 'Os módulos são organizados em `/lib/modules/` identificados com o número de versão `uname -r` correspondente ao kernel em execução.' },
  { id: 'lpic2-201-2', topicId: 2, question: 'Qual destino (target) do "make" é empregado para criar uma imagem moderna e compactada para o kernel Linux?', options: ['make zImage', 'make bzImage', 'make vmlinux', 'make install'], answer: 1, explanation: '`make bzImage` constrói o Big zImage (núcleo comprimido), mitigando os antigos limites de memória no boot.' },
  { id: 'lpic2-201-3', topicId: 2, question: 'Ao configurar o kernel através do código-fonte (source code), qual comando fornece uma interface orientada por menus em modo texto?', options: ['make config', 'make menuconfig', 'make xconfig', 'make defconfig'], answer: 1, explanation: '`make menuconfig` utiliza a biblioteca ncurses para expor menus textuais coloridos de configuração do source tree.' },
  { id: 'lpic2-201-4', topicId: 2, question: 'Qual comando deve ser executado primariamente para carregar um módulo kernel preenchendo automaticamente também os pré-requisitos necessários?', options: ['insmod', 'modinfo', 'modprobe', 'rmmod'], answer: 2, explanation: 'A diferença chave entre o modprobe e o antigo insmod é que ele resolve automaticamente a cadeia de dependências em modprobe.dep.' },
  { id: 'lpic2-201-5', topicId: 2, question: 'O que o arquivo `System.map` registra efetivamente em relação ao Kernel Linux?', options: ['A senha do Bootloader', 'O mapeamento das funções de Kernel em endereços da memória local (Symbol Table)', 'Backup bzImage', 'Logs de Boot'], answer: 1, explanation: 'Atua como uma tabela de endereços de símbolos (Kernel Symbols mapping) vital aos analisadores de falhas (Kernel panic debug).' },

  // Topic 202: System Startup
  { id: 'lpic2-202-1', topicId: 3, question: 'No modelo SysVinit, onde se estipula qual será o Runlevel defaut da máquina no instante de Bootup?', options: ['/etc/inittab', '/etc/runlevel', '/boot/grub/grub.cfg', '/etc/init.d/rcS'], answer: 0, explanation: 'No SysV Legacy, o arquivo que coordena o runlevel é o `/etc/inittab` via id:xxx:initdefault:' },
  { id: 'lpic2-202-2', topicId: 3, question: 'Na distruibuição Ubuntu/Debian, qual script atalho você roda para regravar / reconstruir atualizações para o GRUB 2 de bootloader?', options: ['grub-install', 'grub2-mkconfig', 'update-grub', 'grub-setup'], answer: 2, explanation: 'O Utilitário `update-grub` é um invólucro (Wrapper) oficial na distro Debian para comandar a rotina grub-mkconfig.' },
  { id: 'lpic2-202-3', topicId: 3, question: 'Desejando efetuar manutenção extrema isolada no Host rodando systemD, você acessa este em "Modo Monousuário". Qual Target invocou?', options: ['runlevel1.target', 'rescue.target', 'single.target', 'emergency.target'], answer: 1, explanation: '`rescue.target` recria o análogo de Runlevel 1 (Single User) oferecendo um local sem processos de redes instáveis.' },
  { id: 'lpic2-202-4', topicId: 3, question: 'Onde tipicamente a sintaxe já formatada de configuração principal "Runtime" de GRUB 2 fica assentada em distro padrão?', options: ['/boot/grub/grub.conf', '/boot/grub2/grub2.cfg', '/boot/grub/grub.cfg', '/etc/grub.cfg'], answer: 2, explanation: 'Normalmente, ele deposita seu arquivo Mestre auto-gerado dentro de `/boot/grub/grub.cfg` (ou em grub2/).' },
  { id: 'lpic2-202-5', topicId: 3, question: 'Forçando o repasse de argumento `init=/bin/sh` direto pro GRUB Boot line do Kernel resulta principalmente no que?', options: ['Evade completament o systemd provendo logo a root da shell.', 'Monta modo "Live".', 'Limpa memória System.map.', 'Lança Graphical Interface em fallback VESA.'], answer: 0, explanation: 'Esta instrução força ao Kernel arrancar o RootFS sem disparar a cadeia padrão de PID 1, concedendo permissão shell root.' },

  // Topic 203: Filesystem and Devices
  { id: 'lpic2-203-1', topicId: 4, question: 'Qual sistema concebido com grande foco em alta extensão de arquivos é escalável e escolhido de base na série RHEL 7?', options: ['ext4', 'xfs', 'btrfs', 'zfs'], answer: 1, explanation: 'XFS (da outrora Silicon Graphics) brilha sobre arrays densos e tornou-se a configuração matriz das edições RHEL corporativas.' },
  { id: 'lpic2-203-2', topicId: 4, question: 'Que comando do shell diagnostica profundamente setores físicos e repara blocos defeituosos estruturais de volumes EXT4?', options: ['fsck.ext4', 'e2fsck', 'A e B representam o mesmo', 'xfs_repair'], answer: 2, explanation: 'Na prática, ambas referências remetem ao núcleo nativo do pacote do utilitário `e2fsck`.' },
  { id: 'lpic2-203-3', topicId: 4, question: 'Sobre o `/etc/fstab`, a que se destina explicitamente a função declarada neste documento?', options: ['Configurar IP Networking', 'Registrar fixamente os Pontos de Montagens automáticos requeridos no arranco Systema Host', 'Usuários sudoers', 'Registrar Lojas de Logins SSH RSA'], answer: 1, explanation: 'Configura o Table de partições globais do SO para gerir o Auto-Mounting seguro ao levantar da máquina.' },
  { id: 'lpic2-203-4', topicId: 4, question: 'Pelo S.M.A.R.T. monitoring software `smartctl`, como evocamos rapidamente do Disco o Veredicto Final Passed/Fail (Saúde Abreviada)?', options: ['-a', '-H', '-i', '-t short'], answer: 1, explanation: 'A flag `-H` atesta rapidamente um Sumário de "Hard drive Health Status".' },
  { id: 'lpic2-203-5', topicId: 4, question: 'Para fazer o "Dump" copiando todo formato bruto exato e Byte Block de um Drive DVD `/dev/cdrom` e arquivá-lo como formato .ISO usa-se:', options: ['tar -cvf image.iso /dev/cdrom', 'dd if=/dev/cdrom of=image.iso', 'mkisofs -o image.iso /dev/cdrom', 'cp /dev/cdrom /iso'], answer: 1, explanation: 'A ferramenta poderosa `dd` é mestra para este processo, manipulando Data Block (if=input-file para o /dev e of=output-file).' },

  // Topic 204: Advanced Storage
  { id: 'lpic2-204-1', topicId: 5, question: 'O utilitário standard por linha de comando em Servidores Linux adotado em gerar e recuperar RAID por Software nativo e sua lógica em bloco de Arrays consiste de:', options: ['lvm', 'fdisk', 'mdadm', 'parted'], answer: 2, explanation: 'O Multiple Devices Admin (mdadm) centraliza ativamente toda criação de array `/dev/md0` etc.' },
  { id: 'lpic2-204-2', topicId: 5, question: 'Nos paradigmas RAID, qual Nível consagra a simples Cópia (Mirror Data integral) provendo máxima tolerância a quebra mas carece de agilidade de Striping?', options: ['RAID 0', 'RAID 1', 'RAID 5', 'RAID 10'], answer: 1, explanation: 'RAID 1 reflete com exatidão do conteúdo sem mescla ou parity (Mirror Block por Block).' },
  { id: 'lpic2-204-3', topicId: 5, question: 'Visando escalonar seu pool estático LVM de Grupo de Volumes em Linux. Qual ação insere permanentemente uma nova peça de Disco Físico?', options: ['pvcreate', 'vgextend', 'lvextend', 'vgcreate'], answer: 1, explanation: 'Sob a camada hierárquica lvm `vgextend <grupo> <disco>` prolongará de vez os blocos expansivos disponíveis das VG pools master.' },
  { id: 'lpic2-204-4', topicId: 5, question: 'Em Benchmark do disco no Unix, sob qual parâmetro fazemos com que `hdparm` exclua do teste qualquer Cache local (Buffered Data) para providenciar real velocidade mecânica de IO de leitura Serial?', options: ['-T', '-S', '-t', '-y'], answer: 2, explanation: 'Um scan utilizando o argumento `-t` indica que faremos uma leitura devoradora de Bloco não mitigada por Memórias caches do Chip/Mem Buffer (-T).' },
  { id: 'lpic2-204-5', topicId: 5, question: 'Ao nos referirmos do protocolo corporativo "iSCSI", pontualmente do que é constituído este serviço Target/Initiator?', options: ['Um File Manager NFS', 'Encapsulamento logico da interface local e comando Hardware SCSI pelo pacote padrão Internet de Rede TCP/IP visando mapear Datastores WAN', 'Banco de SQL.', 'Roteamento WiFi WPA2'], answer: 1, explanation: 'Protocolo de armazenamento Storage Network. Engloba as instruções Block level do armazenamento transmitindo as via Lan Pura.' },

  // Topic 205: Network Configuration
  { id: 'lpic2-205-1', topicId: 6, question: 'Substituindo as funções clássicas do comando arp. No pacote evoluído Linux da estrutura `iproute2`, com qual comando avaliamos os registros locais MACs ligados das tabelas Arp Neighbors Cache da Lan?', options: ['arp -n', 'ip neigh show', 'netstat -rn', 'route -n'], answer: 1, explanation: '`ip neigh` acessa todas as designiações de Network adjuntas vizinhas em iproute2 engine e state.' },
  { id: 'lpic2-205-2', topicId: 6, question: 'Baseado na mesmíssima API de Redes moderna (iproute2) para gerenciar o tráfego Linux Roteamento, qual comando expressará a Topologia Global Roteável Default?', options: ['route', 'ip route show', 'netstat -r', 'ifconfig'], answer: 1, explanation: 'A sintaxe em `ip route` supercede a função legada "route config".' },
  { id: 'lpic2-205-3', topicId: 6, question: 'Emitir para a linha C.L.I o parâmetro \'-c 4\' associado a verificação PING gerará por fim:', options: ['Disparo para quatro hosts na pool', 'Exatos e limítrofes disparos de apenas Quatro ICMP de requisições concluindo o software com êxito terminal subsequente', 'Modificará as rotas por 4 port.', 'Criara 4 Ping Alias IPv6'], answer: 1, explanation: 'Designa limite na quantia iterada. \'-c\` é count limits estático.' },
  { id: 'lpic2-205-4', topicId: 6, question: 'Qual ferramenta de utilidade é vital para executar o exame de Sniffers de interceptações e varreduras de capturas puras de Datagrams e Protocol TCP Header para depurar fluxos na tela texto do terminal TTY puro?', options: ['wireshark', 'nmap', 'tcpdump', 'tracepath'], answer: 2, explanation: 'A autoridade histórica sem gráfico UI e máxima utilidade de logar e dissecar Streams do kernel em texto formatado.' },
  { id: 'lpic2-205-5', topicId: 6, question: 'Geralmente para trafegar pela Infra Criptografada Privada, a conexão HTTP Seguridade over TLS, tem reserva associada prioritária porta número?', options: ['80', '21', '22', '443'], answer: 3, explanation: 'Assinado pelo modelo the Assigned Internet HTTPS Socket (TCP/443)' },

  // Topic 206: System Maintenance
  { id: 'lpic2-206-1', topicId: 7, question: 'Num roteiro padronizado sem pacotes Binários .deb ou .Rpm, o rito e a cronologia habitual pautada pra transformar source code `C` tarball descompactados à instalação executável segue as fazes de fluxo:', options: ['make > make install > ./configure', './configure > make > make install', 'make install > ./configure > make', 'untar > make install > ./configure'], answer: 1, explanation: 'Gera variáveis e links de Ambiente de Sistema via configure -> Build do Makefile Source -> Deslocamento pra pasta usr bin/ Systema' },
  { id: 'lpic2-206-2', topicId: 7, question: 'Ao transacionar cópias e Backup remoto o que credencia fundamental a superioridade agilidade nativa do serviço RSync sobre meros CP/SCP commandos brutos de transferências?', options: ['Ele ignora permissões nativamente (Chmods).', 'Não há compressão.', 'Avalia Hash de arquivo, não transmite redundância integral, remetendo tão somente o Delta Block de bits modificados da source ao host final.', 'Nao Requer Cripta SSL.'], answer: 2, explanation: 'Trata com perfeição e checagem os blocos poupando 95% do Tráfeg de atualização incremental BandWidth.' },
  { id: 'lpic2-206-3', topicId: 7, question: 'Que classe abrangente e diagnóstica desempenhada a ferramenta `strace` para o Troubleshooting em Software?', options: ['Identifica RootKits de Portas Redes', 'Hooka-se ao Software alvo, logando no terminal exatas API System Calls trocadas sequencialmente entre este software e o Backend Kernel, evidenciando files não encontrados, locks perms entre outros I/O Erros Internos da thread subjacente.', 'Audita logs Systemd journald.', 'Cria túneis e pipes TCP.'], answer: 1, explanation: 'Intercepta e decupa (Trace) o comportamento raiz entre C library/Program System e chamadas restritas.' },
  { id: 'lpic2-206-4', topicId: 7, question: 'Sendo no LInux que Portas Sockets de IP, Files e Nodes de HDD são abstrações listadas igual "Discriptores de Arquivos", caso deva se descobrir as aberturas ocupadas destas listagens global rodando do Daemon X. Digito a ferramenta clássica utilitária?', options: ['lsof', 'ps', 'top', 'find'], answer: 0, explanation: 'The "List Open Files" Listando quem possui bloqueio em file system. (ex.: umbount blocked issue).' },
  { id: 'lpic2-206-5', topicId: 7, question: 'Qual sintaxe acrônima do `tar` comando é frequentemente memorizada nos Manuais Oficiais para extrair e deszippar a tela console um .tar.gz (GZip Bundle)?', options: ['-cvf', '-xvf', '-zxvf', '-jcvf'], answer: 2, explanation: 'Descongestionante flag z, eXtrai arquivos à arvore base com -x, Mostra logs prolixos via -v, Direcionado via File flag -f. ' },

  { id: 'lpic2-207-1', topicId: 8, question: 'Sobre Tabelas e Record Sets do Domain Server Name BIND de Linux, em caso da solicitação direcionada resolver explicitamente e fixar qual é Máquina Numérica de Versões Antigas IPv4 referente associada puramente e tão somente a um SubDomínio Host local e vis versa. É efetuada neste nó Record:', options: ['MX', 'CNAME', 'A', 'AAAA'], answer: 2, explanation: 'IPv4 Address vinculativos mapeamento "Host -> IP".' },
  { id: 'lpic2-207-2', topicId: 8, question: 'Avaliando um Zone-File textual complexo de Bind recém programado com múltiplas correções a fim não desencadear corrupção ao recarregar de systemD do Serviço named em prod, qual Validação deve evocar pra auditar "sintaxe seca" das records formadas deste mesmo zoneado?', options: ['named-checkconf', 'named-checkzone', 'dns-lint', 'dig'], answer: 1, explanation: 'Este é crucial na fase Linter de simulação estrutural local ao arquivo do diretório.' },
  { id: 'lpic2-207-3', topicId: 8, question: 'Qual premissa dita o papel crucial operatório reservado pelo record classificado como \'MX\' no escopo DNS?', options: ['Fornece Alias espelho entre Dominios de empresas de parceiros CNAMES.', 'Apontará a Hierarquia Ponderada para as IP/Nome Servidores de Entrega (Mail Exchangers) que centralizam ativamente o correio enviado destinado originário à sua corporação.', 'Delegar Rotas de Gateway em Proxy Transparent.', 'Injetar Public keys SPF.'], answer: 1, explanation: 'Determínico e Fundamental da Logística SMTP Server Email (Mx: Mail Exchange Route).' },
  { id: 'lpic2-207-4', topicId: 8, question: 'Visando frear sequestros de tráfego, "Cache Poisoning" local de rotas Domain e Falsificações em Servidor Resolutor em Internet WAN da Atualidade. Os Sysadmin recorrem ao Framework Oficial Criptográfico anexo que Assinará Digitamente o Veracidades das respostas dos Queries de Domínio nomeado como:', options: ['DNS-Over-HTTPS (DoH)', 'TLS', 'DNSSEC', 'TSIG'], answer: 2, explanation: 'As Seguranças Embutidas Domain Name Security Extensions geram a Trust Network com certificados Keys Asymmetrics validando os pacotes Bind Responses originárias e seus IP address devolvidos as requisições puras e primitivas originais da WWW/Top Level Root.' },
  { id: 'lpic2-207-5', topicId: 8, question: 'Localmente por praxe generalizada em SO Systema Distro Rhel ou BSD.. De qual arquivo fixo Absoluto Textual emite o processador demônio Bind toda suas determinações Diretivas Principais Matrix Base Global Options e Include Zones References Options ?', options: ['/etc/bind/bind.conf', '/etc/named.conf', '/var/named/config', '/etc/resolv.conf'], answer: 1, explanation: '`named.conf` compila a arquitetura nativa local ao Demônio global configurado local de Bind em Unix System Hierarchy.' },

  { id: 'lpic2-208-1', topicId: 9, question: 'Em infraestrutura Base Apache (HttpD), qual diretiva principal garante capacidade vital de encapsular escopos paralelos viabilizando o processamento Hosting Simultâneo de Várias Sub-Empresas Nomeadas de URL ou Endereços IP separadamente convivendo integradas num Servidor Apache Dedicado Máquina Servidora Unitária com DocumentRots Destivtos Localizadas num Sata Partição Única Hardware ?', options: ['<Directory>', '<ServerHost>', '<VirtualHost>', '<Website>'], answer: 2, explanation: 'VirtualHost detem isolacionismos autônomos por Binding Porta / Name Servidor / Rotas de App (Logs Separados e Processamentos Lógicas paralelos).' },
  { id: 'lpic2-208-2', topicId: 9, question: 'Sobre o Sucesso esmagador do Serviço "Nginx Server", o pilar técnico primário arquitetural assíncrono que consagrou para Desempenho Crítico Escalonado é focado de originária primordial mente via em :?', options: ['Resoluçao Local e Recursões Database Nativo Integrado em Nxt.js de Scripts Server e PHP DataBase Embutidas LocalHost e Compila Python Automático Fast.', 'Tráfego assíncrono Baseado de Non-Blocking Event-Driven altíssimamente Eficiente frente Conexões Long-Runing para Atender papel Frontal De Camada Reverse Proxys Caches Multiplas Escalonadas, Cargas de Load Balancer Round-Robin Inter-Nodes sem Esforço Pesado Mult-Threading Tradicional bloqueante no sistema CPU.', 'Módulo NAT em Switch Iptables Kernel Baseado em L2 Datagram e VCL.', 'Server Pure Active Diretcory para Microsoft.'], answer: 1, explanation: 'Seu core de arquitetura Não-Bloqueante focado em eventos paralelos o catapultou pra suprir as requisições colossais TCP e repassados em FastCgi as Aplicação API de Backend Backend.' },
  { id: 'lpic2-208-3', topicId: 9, question: 'Um daemon SQUID implementado robustamente entre o Tráfego Endpoint Computador Pessoal Empresa corporativa Cliente e da Nuvem Provedor Redes Internet Backbone externa possui de função técnica mor designada essencial e elementar ao quê em suma ?', options: ['Router Firewal Iptables puro NAT Redirections and VPN Tunel IPSec.', 'Aceleração Caching Web HTTP Proxy Gateway, Otimizando Larguras Bandwidths Frequentes via Banco Local Memória Discos Proxy Request Salvo de Sites, Provendo Logs e Bloqueios Rigorosos ACL Controle Restrições Sites Blacklist Content em IntraNets.', 'Repositório Code CVS.', 'Servidor Mail Externo Push Server SMTP Exim Cloud Relays SMTP.'], answer: 1, explanation: 'A Cache Proxy Gateway proxy e Traffic Shaping é essencial de Corporações.' },
  { id: 'lpic2-208-4', topicId: 9, question: 'Para disponibilizar HTTPS com cadeados de TSL Secure Keys em Apache em modo nativo via requisição e tráfego HTTPS via criptologia OpenSSL e TLS. Requer qual Adicional MÓDULO compilação oficial dinâmico Carregado prévia mente do httpd Core  ?', options: ['mod_rewrite', 'mod_security', 'mod_ssl', 'mod_proxy'], answer: 2, explanation: 'O modulo central de conectividade TLS é o LoadModule Open ssl nativo "mod_ssl"  oferecido com o Daemon Base e pacotes Libary local. ' },
  { id: 'lpic2-208-5', topicId: 9, question: 'Uma implantação Squid Fresh Default de pacote, aguardará as rotas Gateway Interceptor Socket de Clientes escutando especificamente local em Binding em Qual Porta TCP de Transporte Inicial default por definição IANA sem configurações ACL editadas manuais customizadas ?', options: ['80', '443', '3128', '8080'], answer: 2, explanation: 'Porta Oficial Proxy Stand alone no Config Nativo Squid Cache daemon `squid.conf ` = TCP 3128. ' },

  { id: 'lpic2-209-1', topicId: 10, question: 'Ciente as defasagens e incompatibilidades do Sistema Protocolar De Arquivos Compartilhamentos Diretórios Remotos entre Microsoft OS Client Rede e Storage NAS Unix LInux Network System Files Server OS, qual o Software Ponte Definito Famoso Mestre Integrador Server nativo Linux Daemons capaz do Fornecer Server Mapeamento via Protocol SMB/CIFS Network Discovery Compatibilizados aos OS Clients Windows sem Necessidades ADicional de Componentes no Host Windows Explorer Desktop WorkGroup/ Domain Network Integrado ?', options: ['NFS', 'Samba', 'FTP', 'SSHFS'], answer: 1, explanation: 'SAMBA o Conjunto open source Daemons Software e Ferramental provê file system, authentication Network Windows nativa Emulada (NetBios Cifs Domain Controller).' },
  { id: 'lpic2-209-2', topicId: 10, question: 'Indique a via Rota Caminho Certo Raíz Onde Fica Posicionado do Core Configuration Parametric File para ditar as Diretrizes Share Master Options Policies de Regras ACL Permissõe e Folders compartilhados Listings Do Server Daemon SAMBA Service no LInux Padrão LSB Hierarquia Files?', options: ['/etc/smb/smb.conf', '/etc/samba/smb.conf', '/usr/local/samba.cfg', '/var/lib/samba/config'], answer: 1, explanation: 'The Master Samba File is Globalment Assentado and Lida na base `/etc/samba/smb.conf` de todos sistema de Unix Distributions de Praxes.' },
  { id: 'lpic2-209-3', topicId: 10, question: 'O Serviço Remoto Diretório de Protocol `NFS` Montagem, é governado do núcleo central via RPC. Qual o Exato Base File Plain Text Master onde a gente Enumera, Lista Todos os Nós Diretórios Hosts do Server Local e dita SubNets Networks Clients Allowed a obter Mount Connect Remotas das Shares E Permissons do Servidor Unix Linux via Network File System Service ?', options: ['/etc/exports', '/etc/nfs.conf', '/etc/fstab', '/etc/samba/smb.conf'], answer: 0, explanation: '`/etc/exports` É Tabela Global Declarativa Local do Network File Sys. Nele Estipulamos Listas IPs com Atributos Exclusivos (Ro, Rw) de Pastas de Mount Local Compartilhadas Expostas ao Trânsito da Subnet Router LAN Externa via mount -t nfs.' },
  { id: 'lpic2-209-4', topicId: 10, question: 'Executar Systemctl Reset ou Reload no NFS Server no meio do Expediente Crítico Rede Client pode travá-los. Para não interromper Mounts do Rpc Subjetivo Cliente Conectado LInux Vivo "On-the-Fly", qual comando Ferramenta Utilitário aplicamos Refresh Atualizar Sincronia Rápida Nova ACL Injetarda no Host `/etc/exports`  De forma Invisível ao Rede File Remoto?', options: ['nfs-update', 'systemctl reload nfs', 'exportfs -a / -r', 'mount -a'], answer: 2, explanation: '`exportfs -r` Reload As Changes Refresh do Cache NFS System Local para Mounts Subjacentes OnThe Fly, Evitando Kernel Panic and Desconexão File System NFS.' },
  { id: 'lpic2-209-5', topicId: 10, question: 'Usuários Unix Nativos Linux no OS (Criados com Useradd Password Standard local Etc Shadow) Precisam de Banco Local em Samba para Efetuar Mapear Senha Segura via SMB Auth Rede Cifs e Efetiva Login Compartilhamentos Microsoft Folders SAMBA. Qual SubComando CLI Samba Server Cria Ativa Adiciona Mapeamento Adicional Password Seguro de Usuário Unix Atrelado Pro Daemons SAMBA Passwords Server Local Database Unix  OS Local Tool ?', options: ['smbpasswd -a', 'useradd', 'passwd', 'pdbedit -n'], answer: 0, explanation: 'The `smbpasswd -a nome` Insere Cadastra Link Ativando O HASH Seguro de Usuário SMB Network para ser compatível em Password Protocol Client do Banco SAMBA Local SMB.' },

  { id: 'lpic2-210-1', topicId: 11, question: 'Num contexto rede local Lan Complexa Administrativa TCP e Endpoints, O Serviço Daemon Central Responsável Para Atribuir Automaticamente Concessões Lease Empréstimo Automática e Gestor Remoto de Blocos Subredes e Parâmetros Rotas IP Mask Network Dinântica Massiva em Host Clients é Nomeado Server Oficial Daemon Protocolo :', options: ['DNS', 'DHCP', 'ARP', 'ICMP'], answer: 1, explanation: 'Configurações de Router, Gateway Address e IPs de Hosts Network Nodes Resolutor Automatics Clients IP Assigment (DHCP Dynamic Host Conf Prot).' },
  { id: 'lpic2-210-2', topicId: 11, question: 'A implementação Fundamental Pluggable Authentication Modules `PAM` Base Engine Linux System Tem Em Essência Conceito Arquitetural Fiel Em Atuar Provendo : ', options: ['Arquitetura API Central para Gerenciamento e Transição Intercalares Abstratos Independente Interligando os Daemons e Binarios Locais as Validações Regras Complexas de Authentification Layers System, Sem Modificação Nos Fontes Dos Software Servidores, Desacoplando o Frontend Code Login e Modulo Backend Verifier Credenciais Auth Methods.', 'Redutor Proxy Database IPSec.', 'O Componente Kernel Nativo De Compilação e Virtualização Container.', 'Firewall Nativo do Router Gateway do System Local Server e DHCP MACs Addresses.'], answer: 0, explanation: 'PAM Desacopla as Aplicações de como, e com QUAIS Bibliotecas eles efetuarão Validações Password Biométricas Smart Cards PAM e LDAP etc, O Software chama The PAM E O Pam Configura Rota Regras Complexas.' },
  { id: 'lpic2-210-3', topicId: 11, question: 'Serviço Central LDAP Network e Bases LDAP Directory Structure corporativa corporativo Famoso Em OpenLDap Server System. É Fundamentalizado Utilizado Primária Original Historica Característica Padrão Atendendo o que Na T.I Pratica Redes Diretórios Identity Geral Unix Network ? ', options: ['Directory Central Leve Fast Query Otimizado Para Leitura Constante de Information Estrutural Focado a Identidade de Credenciais Network Identity, Groups, Listas AddressBooks e Authentification Master SingleSign Centralizer Trees de Domínio Rede Corporativo Multiplos Clients OSs Em Rede. ', 'É Storage NAS Físico de Bloco.', 'O Sistema Backup Incremental Logico Tape Server Local.', 'Ferramenta Boot Pxe SysVinet Local Unix Daemon.'], answer: 0, explanation: 'Sistemas Dretórios e Autenticadores Identity Providers Base Em Redes Enterprise LDAP Server Structure DIT e Objetos OU.' },
  { id: 'lpic2-210-4', topicId: 11, question: 'Avançado Infra OpenVpn Tunnel Network Software Client / Server Protocol System Device Adpter Interface. Caso a Virtual Adapter VPN esteja Selecionado Adpter tipo Openvpn Routing Mode Device Driver Engine de Kernel "TUN" Adaptador , Este Modelo Interface Consequentemente Opera Transita e Encaminha De Maneira Criptografada e Fechada Somente Os Datagramas De Rede e Camada OSI Layer Respectiva Sendo e Exclusivamente da Região de Qual Segmento Protocolo Roteamento Em Específico Encapsuladas IP Sec ?', options: ['Camada Layer 1 Fisico RJ45 Pura Ethernet Bits Frequences Mac Criptografada L2 Switching Pure Hub.', 'Somente da Camada OSI Network Roteável Roteamento L3 Protocolo Base Tráfegos Pacote IPv4 e IPv6 Nativo IP Header Routing Forward , Eliminando Tráfego BroadCast Ethernet Frames Broadcast L2 e Topologias Físicas Inuteis Em L3 Nat Routing Ext.', 'Camadas Transport L4 Sockets Session Port TCP HandShakers Apenas TCP Stream Tun.', 'Proxy Port 80 L7 App Layers Caching Http Proxy Cripto Rest Request.'], answer: 1, explanation: 'Dispositivo Adaptador Túnel Virtuais Tunnel Mode `TUN` Interfaces Encapsulam Tráfego em Protocol layer Layer-3. Diferente De `TAP` Interface que encapsula MAC frame Bridging Level OSI 2.' },
  { id: 'lpic2-210-5', topicId: 11, question: 'O Daemon Componente do Protocol OpenVPN Backend Systema Escutando em Interfaces External Cloud e Transportes Daemons de Tunnel Binding, Optará por Convenção e Deficulde Config Cinetifica Predefinida Oficial Otimizada De Protocol Socket Transports Portos Network Escuta Default Bind :?', options: ['1194 UDP', '22 TCP', '443 TCP', '53 UDP'], answer: 0, explanation: 'Porta IANA VPN Assigment Em Otimizadas Operações Transporte Pdrões É Porta E UDP Sem Atrasos Lags TCP Windows Streams e Congestionamentos Atrasados Defaulting `1194` Porta `UDP` ' },

  { id: 'lpic2-211-1', topicId: 12, question: 'Na Espiral de Ferramental do Systemas Globais UNIX Server System Correio Eletrônico, Qual A Denominação Protocolo Oficial Global TCP Usado Exclusivamente Pela Internet Network Entre Os Mail Transfer Agents Nodos Sendmail MTA Postfix Entrega Remota Para Transferência Envio de Entregas Mails Transmissões Envelopes Base Messages Network Relay Port Server ?', options: ['POP3', 'IMAP', 'SMTP', 'SNMP'], answer: 2, explanation: 'Simple Mail Trasnfer Protocols (TCP 25). É The Core Tranksfer Inter Domain Server Server Nodes For Message Envelope Envio Envios Routing Mail Payload Sendings (SMTP)' },
  { id: 'lpic2-211-2', topicId: 12, question: 'Administração Daemon MTA Core Postfix Linux Server Mail.. De Acordo À Especificação Oficiais Pastas de Base Configuration Postfix, Qual Dentre Arquivo Fundamental Determina A Inteligência Base Geral Parametric Onde Colocamos E Escrevemos Customizações Opciones Limits IP Trusteds Dominio FQDN Local Virtual Host Server Settings Network Security Parameters Configuration Global Options ?', options: ['/etc/postfix/master.cf', '/etc/postfix/main.cf', '/etc/mail/sendmail.cf', '/var/spool/postfix/config'], answer: 1, explanation: '`/etc/postfix/main.cf` Ficheiro Texto É The Central Brain Of Parametric And Logics Local Server Domains Access Network Rules For The Process Postifx Engine E Core Systemas Regras Customização Postfix Mails Options Global Engine Controlers. Local System Base Mails.' },
  { id: 'lpic2-211-3', topicId: 12, question: 'Após Finalização Servidor SMTP, Os End Users Desktop Cellphone Network Applications Local MUA Devices Mail Client Softwares Precisaram se Connectar Remote Via Poling Secure Push/Pull Folder Sync. A Ferramenta Puxar Email Padrão Pop /Imap Sockets Mail Deferida Para Desempenhar De Extrema Modernidade Atual Linux e Alta Performance Leitura Client Asynchronous Retrieval Mbox and Caching Remote Folder IMAP Client Mail Retrieving Application e :?', options: ['Postfix', 'Dovecot', 'Procmail', 'Squid'], answer: 1, explanation: 'DOVECOT É Lider Standard Open-Sourced Server Base Para MDA Protocol Delivery End-Users IMAP/POP3 Sockets Server e Retriver Service Daemons Auth Seguras e Leitura Rapida Local Folders e Clients Sync Mobile E-mail Softwares' },
  { id: 'lpic2-211-4', topicId: 12, question: 'Um Script Linguagem Filter Configurado Tipo Delivery Sieve Sieve-Script e Softwares de Roteamentos Tipo `Procmail` Local System Agents Serve Especialmente Pra Adiantamentos Finais Como Mapeamento Da Entrega, Estes Tipicamente Realizam Funções Exatas Aos Mails Delivery Recebidos Dos MTA Backend Com Objetivos Explicito Qual Opções Em Mail Delivery Routing Folder Inbox Users Caixas Locais ?', options: ['Agir Invocos Filtros, Dissecando Expressões Regex de Headers Conteúdo Corpo Content Local de Mails Previamente Na Hora Do Entrega Gravando Redirecios Descartando Span Junk Ou Processando Regrinhas Específicas Personalizados De Redireções Automatico Pastas Arquivos Customizados Ao Escrever Ao Drive MBox Endereço Específico Usuário Final Box Messages.', 'Aceleração Carga HTTP Caching Database Criptografia DNS de Root.', 'DHCP DHCP Dynamic Ip Pools Database.', 'OpenVAS Vulnerabilities Auto Scanner Audit.'], answer: 0, explanation: 'Local Delivery Agents ou MDA Agents. Filtram e Encadeam Processamento Filtros Locais Custom (Scripts Conditionals Regex de Delivery Sieve Protocol) Após Ser Sucsessful Recebido SMTP Postifix Server Before Escrever Fisicamente Na Unidade Drive User Account Mails Inboxes Pasta Final.' },
  { id: 'lpic2-211-5', topicId: 12, question: 'Rotina Basilar de SendMail Alias Forward Mail Local /etc/aliases Aliasing Routing Accounts: Modificado Um Plain-Text Record Root: Admin no Texto Fonte. Tem Regra Em Qual Acionamento Bash Comando Certo Shell Executa Ferramenta Core Para Regerar Traduzir Fazer Re Hash Database .DB Binary Map Format de Aliases Lida Mais Rápido Pelo MTA Unix Daemon Process Sem Quebras Formato e Velocidade Fast Hash?', options: ['makemap', 'newaliases', 'postmap', 'systemctl reload postfix'], answer: 1, explanation: 'O App Wrapper Binário Helper CLI `newaliases` Força o Recálculo Local Compile Tool Fast Generation C++ Da Format Plaintext .aliases Transmutando-O e Sobrescrevendo Hash Indexação Alias.DB Para Leitura Otimizada Binária Constante Rápida Fast Query Map Engine Do Daemon e Processes Kernel Do MTA Server Program Linux Local' },

  { id: 'lpic2-212-1', topicId: 13, question: 'Contexto System Administration Kernel Level Linux NetFilter Iptables FireWall Tool Protocol CLI LInux Core Module Chains and Tables Routing Logics. A Tabela Específica Exclusiva Custom Designada Construída No Cerne Para Receber Alocar Implementar Inclusividades Tradução Dinâmicas Fowards Manipulação SubRedes Masqueradings Port Forwardings e Tramslaçoes Translators IP Alterações SNAT and DNAT Packet Change Source Destination IPs Rules : Chamamos Certa E Exatamente Qual das Abaixos Table Option System Netfilter LInux Kernel Tab :?', options: ['filter', 'mangle', 'nat', 'raw'], answer: 2, explanation: 'A Tabela `nat` Tem Triggers Especiais de Pre-Routing ou Post-Routing. Construída Focada Principal Somente Praticar Alterações Substituições Mudanças NAT Translactions Port-Forward Redireções e Substituições IP Headers Roteação Camadas NAT Privadas LAN a Pùblicas IPS E ViceVersas.' },
  { id: 'lpic2-212-2', topicId: 13, question: 'Ferramenta Poderosa Python Scripters OpenSource Unix Daemon LInux Network System Security Auto Banning Systema Bloqueio E Monitorações SysLogs Intruder Actions Detection Attack BruteForces e Dictionary Crack. Software Lê Pattern Regular Expression Auth.Log Access Apache e Gera Iptables Block Temporary Rejets Time-Based Timeout Ao Atacante External Connection Daemon Application O Nome Exato E Notável Software Sistema de Analise e Blocagens Scripting Tool Ban IPs:?', options: ['Snort / Suricata', 'Fail2ban', 'Nmap', 'OpenVAS/Nessus'], answer: 1, explanation: 'Software Scripting Inteligente Fail2Ban Le Monitora Dinâmicamente Tail Log Application Patterns RegExp. Ao Achar Ex.: Failed Pass x4 Times Login Auth Daemon Syslogs, Injeta Temporáriamente Iptables Rule Reject Dropping Restrutir IP Bloqueando Offence Block E Evadindo Brute Attacker.' },
  { id: 'lpic2-212-3', topicId: 13, question: 'Na Area e Avaliação Redes Lan CiberSegurança e CiberAuditoria OSINT Sysadmin Ethical Hacker Port Services Mapping External Protocol Discovery And Analysis Tool. O Canivete LUA Scripts Port Map Varreduras Sweep And Services Version System OS FingerPritns Remote Discovery Sweep CLI Ferramental Network Software App Command Tools Reconnaisance Open Ports Audit Network Tool Base Name e Chamado Famoso Exato Terminal App Command Software Tool Is :?', options: ['tcpdump stream capture', 'wireshark analizer LAN', 'nmap portscan footprint and version checker', 'ping sweeping scanner'], answer: 2, explanation: 'Network Mapper Tool NMAP A Ferramenta Master Padrão Terminal App Base Ouro Scanning Varreduras Recon Port And Service And OS Version Software Mapping Audit Vulnerabilty Information Gathering Information.' },
  { id: 'lpic2-212-4', topicId: 13, question: 'Project Open Source Avançado Server Client Vulnerability Scanning Appliance Database CVE Patch Database e Security Assurance GVM Architecture Fork de Historico Software Fechado Nessus, Hoje Dedicado Amplamente Teste De Massivos Sistemas Hosts Servers Auditorias Ativas LInux System Corporativas E Reportes Assesments Fallas Vulnerabilidades Framework Ecosystem Server Audit Is The Project Tool App Application :?', options: ['Um BASH SHELL SCRIPT De Monitoracao RAM and DISCOS IO.', 'A Ferramenta "OpenVAS" Vulnerability Assessment System Scanner Suite GVM Ecosystem Project Security Auditing Framework DataBase Engine.', 'Ferramenta GUI C++ para Desktop Iptables.', 'Banco Dados MySQL.'], answer: 1, explanation: '`OpenVAS` Greenbone Vulnerability Management Framework Assessment Suite App Framework Server Scan and CVE Engine Analysis Network Auto-Testing Fallas Audits.' },
  { id: 'lpic2-212-5', topicId: 13, question: 'Ao Parametrizarmos Iptables Firewall Rule Base Security Hardening LInux Table `filter`. Qual Opção De Comandos Script De CLI Iptables Modificaria Permanente De Default Inicial Passivo e Liberal Ao Extremo Configurando De Fato a Regra Base De Fundamentos De Corrente Chamada Default `POLICY` da Corrente de Entrada Network INPUT Do Server Para Causa de Ação Consequencia Omissa Padrão Fixa de Queima Direta Destruição Silênciosa Gota Fogo Packet DROP Baseada em Política Base Omissa Silênciosa Fechada e Blindada a Rede Server Baseada em `DROP` Security System Command LInux Base Is :?', options: ['iptables -A INPUT -j DROP', 'iptables -P INPUT DROP', 'iptables -I INPUT DROP', 'iptables -D INPUT DROP'], answer: 1, explanation: 'The CLI Param `-P` Defines And Setup Static DEFAULT POLICY Das Block Rules das Chains Netfilter. INPUT DROP Define Fechamento Cego De Todas as Conexões Sem Allow Explícito De Entrada Pelo Administrador Baseado Na Corrente INPUT Tráfico.' },
// --- NOVO BATCH 1 (Tópicos 200-204) ---
  { id: 'lpic2-200-6', topicId: 1, question: 'O que significa a coluna `wa` na saída do `vmstat`?', options: ['Aguardando CPU', 'Aguardando E/S (I/O Wait)', 'Aguardando rede', 'Aguardando alocação de memória'], answer: 1, explanation: 'A coluna `wa` indica a porcentagem de tempo que a CPU ficou ociosa enquanto o sistema tinha solicitações de E/S de disco pendentes.' },
  { id: 'lpic2-200-7', topicId: 1, question: 'Qual comando fornece um resumo rápido das médias de carga do sistema (Load Averages) dos últimos 1, 5 e 15 minutos?', options: ['w', 'uptime', 'Ambos (A e B)', 'sar'], answer: 2, explanation: 'Tanto o `w` quanto o `uptime` exibem as Load Averages do sistema.' },
  { id: 'lpic2-200-8', topicId: 1, question: 'Qual é o principal protocolo usado pelo MRTG para coletar dados de dispositivos de rede?', options: ['SSH', 'SMTP', 'SNMP', 'HTTP'], answer: 2, explanation: 'O MRTG (Multi Router Traffic Grapher) depende principalmente do SNMP (Simple Network Management Protocol) para coletar métricas.' },
  { id: 'lpic2-200-9', topicId: 1, question: 'Qual comando mostra estatísticas para interfaces de rede, incluindo pacotes descartados e erros de overrun?', options: ['netstat -i', 'netstat -r', 'netstat -tulnp', 'ifconfig -a'], answer: 0, explanation: '`netstat -i` exibe uma tabela de todas as interfaces de rede e suas respectivas estatísticas de transmissão e recepção.' },
  { id: 'lpic2-200-10', topicId: 1, question: 'Qual valor de memória na saída do comando `free` é o mais indicativo de quanta memória está disponível para iniciar novas aplicações sem swap?', options: ['total', 'used', 'shared', 'available'], answer: 3, explanation: 'A coluna `available` estima quanta memória está disponível para iniciar novas aplicações sem causar swapping.' },
  { id: 'lpic2-200-11', topicId: 1, question: 'Como você configura o Collectd para armazenar métricas de forma eficiente ao longo do tempo?', options: ['Escrever em arquivos CSV', 'Escrever via RRDtool', 'Apenas escrever no MySQL', 'Escrever no syslog'], answer: 1, explanation: 'O Collectd frequentemente usa o plugin RRDtool (Round Robin Database) para armazenar dados de séries temporais de forma eficiente.' },
  { id: 'lpic2-200-12', topicId: 1, question: 'Qual ferramenta é projetada especificamente para mostrar o uso de E/S por processo em tempo real, semelhante ao `top`?', options: ['iotop', 'iostat', 'ioping', 'blktrace'], answer: 0, explanation: 'O `iotop` exibe uma interface semelhante ao top com a largura de banda de leitura e escrita de E/S por processo.' },
  { id: 'lpic2-200-13', topicId: 1, question: 'O que altos valores de `si` e `so` no `vmstat` indicam fortemente?', options: ['Congestionamento de rede', 'Gargalo de CPU', 'Falta de memória e swapping intenso', 'Falha de hardware de disco'], answer: 2, explanation: 'Altas taxas de Swap-In (`si`) e Swap-Out (`so`) indicam que o sistema está movendo ativamente memória para o disco devido à exaustão da RAM.' },
  { id: 'lpic2-200-14', topicId: 1, question: 'Qual comando lista todos os sockets TCP e UDP em escuta junto com o ID do processo (PID)?', options: ['ss -tulnp', 'netstat -rn', 'ip route', 'arp -a'], answer: 0, explanation: '`ss -tulnp` (ou netstat -tulnp) lista as portas TCP/UDP em escuta e os IDs de processo associados.' },
  { id: 'lpic2-200-15', topicId: 1, question: 'O que é uma "Baseline" no planejamento de capacidade?', options: ['A capacidade máxima do servidor', 'O requisito mínimo de RAM para boot', 'Dados históricos que representam o comportamento normal do sistema', 'O limite físico da placa de rede'], answer: 2, explanation: 'Uma baseline é um estado normal conhecido do sistema, registrado ao longo do tempo para comparação com anomalias ou crescimento futuro.' },

  { id: 'lpic2-201-6', topicId: 2, question: 'Qual comando limpa completamente a árvore de diretórios do kernel, removendo todos os arquivos compilados e o arquivo .config?', options: ['make clean', 'make mrproper', 'make distclean', 'make wipe'], answer: 1, explanation: '`make mrproper` remove todos os arquivos gerados, incluindo o `.config` e vários arquivos de backup.' },
  { id: 'lpic2-201-7', topicId: 2, question: 'Qual é o propósito do comando `depmod`?', options: ['Remover um módulo', 'Gerar o arquivo modules.dep para o modprobe', 'Mostrar detalhes sobre módulos', 'Compilar módulos'], answer: 1, explanation: '`depmod` analisa os módulos do kernel e cria uma lista de dependências (`modules.dep`) usada pelo `modprobe`.' },
  { id: 'lpic2-201-8', topicId: 2, question: 'Qual ferramenta reconstrói automaticamente módulos do kernel para drivers de terceiros (como Nvidia) ao instalar um novo kernel?', options: ['depmod', 'dracut', 'DKMS', 'kmod'], answer: 2, explanation: 'O DKMS (Dynamic Kernel Module Support) é um framework que recompila módulos externos do kernel quando um novo kernel é instalado.' },
  { id: 'lpic2-201-9', topicId: 2, question: 'Como você pode visualizar a configuração ativa no momento do kernel em execução (se suportado pelo kernel)?', options: ['cat /proc/kcore', 'zcat /proc/config.gz', 'cat /sys/kernel/config', 'dmesg | grep config'], answer: 1, explanation: 'Se o `IKCONFIG_PROC` estiver ativado, a configuração atual do kernel está acessível via `/proc/config.gz`.' },
  { id: 'lpic2-201-10', topicId: 2, question: 'Qual comando lista todos os módulos do kernel atualmente carregados?', options: ['lsmod', 'modinfo', 'modprobe -l', 'infomod'], answer: 0, explanation: 'O `lsmod` formata o conteúdo de `/proc/modules` para mostrar quais módulos estão carregados na memória.' },
  { id: 'lpic2-201-11', topicId: 2, question: 'Qual é a principal diferença entre `initrd` e `initramfs`?', options: ['initrd é um arquivo cpio; initramfs é uma imagem de dispositivo de bloco', 'initramfs é um arquivo cpio extraído em um tmpfs; initrd é uma imagem de dispositivo de bloco', 'initrd é apenas para UEFI', 'initramfs não pode carregar módulos'], answer: 1, explanation: '`initramfs` é uma abordagem mais moderna que usa um arquivo cpio compactado carregado em um tmpfs.' },
  { id: 'lpic2-201-12', topicId: 2, question: 'Qual comando exibe informações sobre um módulo do kernel, como autor, descrição e parâmetros aceitos?', options: ['lsmod', 'modprobe -d', 'modinfo', 'insmod -i'], answer: 2, explanation: '`modinfo` extrai e exibe informações do próprio arquivo objeto do módulo.' },
  { id: 'lpic2-201-13', topicId: 2, question: 'Qual comando lê o `sysctl.conf` e aplica os parâmetros de kernel imediatamente?', options: ['sysctl -w', 'sysctl -a', 'sysctl -p', 'sysctl -r'], answer: 2, explanation: '`sysctl -p` carrega as configurações do `/etc/sysctl.conf` (ou arquivo especificado) para o kernel em execução.' },
  { id: 'lpic2-201-14', topicId: 2, question: 'Onde o `udev` procura por regras personalizadas para eventos de hardware?', options: ['/etc/udev/rules.d/', '/lib/udev/rules.d/', 'Ambos (A e B)', '/var/run/udev/'], answer: 2, explanation: 'O `udev` lê as regras padrão em `/lib/udev/rules.d/` e as regras administrativas personalizadas em `/etc/udev/rules.d/`.' },
  { id: 'lpic2-201-15', topicId: 2, question: 'Qual comando remove um módulo do kernel em execução, desde que ele não esteja em uso?', options: ['rmmod', 'insmod -r', 'modprobe -r', 'Ambos (A e C)'], answer: 3, explanation: 'Tanto `rmmod` quanto `modprobe -r` podem ser usados para remover módulos; o `modprobe -r` também remove dependências de forma limpa.' },

  { id: 'lpic2-202-6', topicId: 3, question: 'Qual comando define o target padrão do systemd para o modo gráfico (equivalente ao runlevel 5)?', options: ['systemctl set-default graphical.target', 'systemctl isolate graphical.target', 'systemctl default graphical.target', 'ln -s /lib/systemd/system/graphical.target /etc/inittab'], answer: 0, explanation: '`systemctl set-default` altera o target de boot padrão atualizando o link simbólico `/etc/systemd/system/default.target`.' },
  { id: 'lpic2-202-7', topicId: 3, question: 'Qual tecla geralmente permite acessar o menu de boot do GRUB 2 para editar parâmetros do kernel se ele estiver oculto?', options: ['F8', 'F12', 'Shift ou Esc', 'Enter'], answer: 2, explanation: 'Manter `Shift` pressionado (sistemas BIOS) ou pressionar `Esc` (sistemas UEFI) interrompe o boot do GRUB 2 e exibe o menu.' },
  { id: 'lpic2-202-8', topicId: 3, question: 'O que o comando `systemctl isolate` faz?', options: ['Reinicia o sistema', 'Muda o estado operacional atual para um novo target, interrompendo serviços desnecessários', 'Desativa interfaces de rede', 'Executa um chroot em outro ambiente'], answer: 1, explanation: '`isolate` muda o sistema imediatamente para um novo target (semelhante à mudança de runlevel no SysV).' },
  { id: 'lpic2-202-9', topicId: 3, question: 'Qual arquivo contém configurações globais (como timeout e entrada padrão) usadas pelo `grub-mkconfig` para gerar a configuração do GRUB 2?', options: ['/etc/grub.d/00_header', '/boot/grub/grub.cfg', '/etc/default/grub', '/boot/grub/menu.lst'], answer: 2, explanation: '`/etc/default/grub` contém variáveis como `GRUB_TIMEOUT` e `GRUB_CMDLINE_LINUX` que controlam a geração do arquivo.' },
  { id: 'lpic2-202-10', topicId: 3, question: 'O que é PXE?', options: ['Um formato de tabela de partição', 'Um método para bootar um SO pela rede usando DHCP e TFTP', 'Um bootloader Linux para ARM', 'Um tipo de unit do systemd'], answer: 1, explanation: 'O Preboot eXecution Environment (PXE) permite que placas de rede obtenham um bootloader e kernel de um servidor na rede.' },
  { id: 'lpic2-202-11', topicId: 3, question: 'Qual diretório contém os scripts modulares executados pelo `grub-mkconfig`?', options: ['/etc/default/grub', '/etc/grub.d/', '/boot/grub/scripts/', '/lib/grub/'], answer: 1, explanation: 'O diretório `/etc/grub.d/` contém scripts executáveis (como o 10_linux) que escaneiam o sistema durante a geração do grub.cfg.' },
  { id: 'lpic2-202-12', topicId: 3, question: 'O que é o `systemd-boot`?', options: ['Um wrapper para o SysVinit', 'Um gerenciador de boot UEFI leve', 'Um plugin para o GRUB', 'Um tema do Plymouth'], answer: 1, explanation: 'O `systemd-boot` (antigo gummiboot) é um gerenciador de boot UEFI simples integrado ao systemd.' },
  { id: 'lpic2-202-13', topicId: 3, question: 'Qual parâmetro de kernel você pode passar no GRUB para ignorar a autenticação caso tenha esquecido sua senha de root?', options: ['root=/dev/null', 'init=/bin/bash', 'skip_auth=1', 'runlevel=0'], answer: 1, explanation: 'Adicionar `init=/bin/bash` (ou /bin/sh) monta o root e inicia imediatamente uma shell de root sem pedir senha.' },
  { id: 'lpic2-202-14', topicId: 3, question: 'Qual comando gera um ramdisk inicial (initramfs) em sistemas Red Hat / CentOS?', options: ['mkinitcpio', 'mkinitrd / dracut', 'update-initramfs', 'initramfs-build'], answer: 1, explanation: 'Sistemas baseados em RHEL historicamente usavam `mkinitrd` e agora usam nativamente o `dracut` para criar o initramfs.' },
  { id: 'lpic2-202-15', topicId: 3, question: 'Qual script no SysVinit é tipicamente responsável por executar os scripts rc para o runlevel definido?', options: ['/etc/rc.local', '/etc/init.d/rc', '/sbin/runlevel', '/bin/sh'], answer: 1, explanation: 'O script `/etc/init.d/rc` é chamado pelo init com o runlevel como argumento para iniciar/parar serviços em `/etc/rcX.d/`.' },

  { id: 'lpic2-203-6', topicId: 4, question: 'Qual comando exibe a geometria de hardware e as partições de um disco rígido?', options: ['df -h', 'lsblk', 'fdisk -l', 'Ambos (B e C)'], answer: 3, explanation: 'Tanto o `lsblk` quanto o `fdisk -l` descrevem dispositivos de bloco e partições (o fdisk mostra detalhes de geometria).' },
  { id: 'lpic2-203-7', topicId: 4, question: 'Qual comando converte um sistema de arquivos ext3 para ext4 sem perda de dados?', options: ['tune2fs -O extents,uninit_bg,dir_index /dev/sda1', 'mkfs.ext4 /dev/sda1', 'fsck.ext4 -y /dev/sda1', 'parted /dev/sda1 convert ext4'], answer: 0, explanation: 'O `tune2fs` permite ativar recursos do sistema de arquivos em uma unidade existente; adicionar as features do ext4 efetivamente o converte.' },
  { id: 'lpic2-203-8', topicId: 4, question: 'Qual ferramenta altera o UUID de um sistema de arquivos ext2/ext3/ext4?', options: ['uuidgen', 'blkid', 'tune2fs -U', 'xfs_admin'], answer: 2, explanation: '`tune2fs -U [UUID|random] /dev/sdX` altera o UUID do filesystem em sistemas ext.' },
  { id: 'lpic2-203-9', topicId: 4, question: 'Qual opção no `/etc/fstab` monta o sistema de arquivos em modo somente leitura?', options: ['rw', 'ro', 'noexec', 'nosuid'], answer: 1, explanation: 'A opção `ro` significa Read-Only.' },
  { id: 'lpic2-203-10', topicId: 4, question: 'Qual comando fornece informações sobre o status e a fragmentação de um sistema de arquivos XFS?', options: ['xfs_repair', 'xfs_info', 'xfs_db', 'Nenhuma das anteriores'], answer: 1, explanation: 'O `xfs_info` exibe detalhes sobre a geometria e o layout de um sistema de arquivos XFS montado.' },
  { id: 'lpic2-203-11', topicId: 4, question: 'Como você pode apagar com segurança um disco rígido (/dev/sdb) sobrescrevendo-o com dados aleatórios?', options: ['dd if=/dev/urandom of=/dev/sdb bs=1M', 'rm -rf /dev/sdb', 'mkfs.ext4 /dev/sdb', 'fdisk -w /dev/sdb'], answer: 0, explanation: 'Usar o `dd` para ler do `/dev/urandom` sobrescreve fisicamente a unidade de destino com dados binários imprevisíveis.' },
  { id: 'lpic2-203-12', topicId: 4, question: 'O que o comando `badblocks` faz?', options: ['Formata o disco', 'Procura por setores fisicamente danificados em um dispositivo', 'Repara o jornal do sistema de arquivos', 'Identifica RAM defeituosa'], answer: 1, explanation: 'O `badblocks` realiza testes de leitura/gravação em setores para identificar blocos fisicamente inutilizáveis na mídia de armazenamento.' },
  { id: 'lpic2-203-13', topicId: 4, question: 'Qual comando btrfs cria um snapshot gravável de um subvolume?', options: ['btrfs subvolume snapshot', 'btrfs snap create', 'lvcreate -s', 'btrfs-image'], answer: 0, explanation: '`btrfs subvolume snapshot <source> <dest>` cria um snapshot copy-on-write.' },
  { id: 'lpic2-203-14', topicId: 4, question: 'O que é o `autofs`?', options: ['Uma ferramenta para formatar discos', 'Um daemon que monta automaticamente sistemas de arquivos sob demanda', 'Um substituto para o GRUB', 'Um roteador de pacotes de rede'], answer: 1, explanation: 'O `autofs` permite a montagem automática (monta apenas quando um usuário acessa um diretório específico) e a desmontagem automática.' },
  { id: 'lpic2-203-15', topicId: 4, question: 'Qual utilitário de criação de mídia óptica cria uma imagem de sistema de arquivos ISO9660?', options: ['cdrecord', 'mkisofs', 'growisofs', 'wodim'], answer: 1, explanation: '`mkisofs` (ou genisoimage) pega uma árvore de diretórios e gera um arquivo de layout ISO9660 para gravação.' },

  { id: 'lpic2-204-6', topicId: 5, question: 'Como você reduz com segurança o tamanho de um Logical Volume no LVM?', options: ['lvresize -L -10G /dev/vg/lv', 'Primeiro reduz o sistema de arquivos no LV, depois reduz o LV', 'Primeiro reduz o LV, depois reduz o sistema de arquivos', 'Não se pode reduzir um LV'], answer: 1, explanation: 'Deve-se encolher o sistema de arquivos (ex: resize2fs) ANTES de reduzir o LV para evitar perda de dados nas bordas.' },
  { id: 'lpic2-204-7', topicId: 5, question: 'Ao gerenciar um array RAID 5 via software with the `mdadm`, what happens if a disk fails?', options: ['Os dados são perdidos permanentemente', 'O array continua operando em modo degradado, usando paridade para calcular dados faltantes', 'O sistema sofre um kernel panic imediato', 'O array muda para RAID 0'], answer: 1, explanation: 'O RAID 5 pode tolerar a falha de exatamente um disco e continuará rodando em modo degradado até a reconstrução.' },
  { id: 'lpic2-204-8', topicId: 5, question: 'Qual comando inicia uma sessão iSCSI para encontrar alvos (targets) em um servidor?', options: ['iscsiadm -m discovery -t sendtargets -p <IP>', 'iscsid --scan', 'mount -t iscsi', 'lvscan'], answer: 0, explanation: '`iscsiadm` é a ferramenta de linha de comando para interagir com o iniciador Open-iSCSI para descoberta e login.' },
  { id: 'lpic2-204-9', topicId: 5, question: 'O que o comando LVM `vgdisplay` mostra?', options: ['Apenas volumes físicos', 'Apenas volumes lógicos', 'Atributos do Volume Group como tamanho total, PEs livres e PEs alocados', 'UUIDs do sistema de arquivos'], answer: 2, explanation: '`vgdisplay` fornece metadados sobre Volume Groups, incluindo detalhes sobre a capacidade de Physical Extents (PE).' },
  { id: 'lpic2-204-10', topicId: 5, question: 'Como você adiciona um disco sobressalente (spare) a um array RAID existente do `mdadm` (/dev/md0)?', options: ['mdadm --add /dev/md0 /dev/sdX', 'mdadm --grow /dev/md0 --size=spare', 'mdadm --create /dev/md0 /dev/sdX', 'Não se pode adicionar spares a arrays ativos'], answer: 0, explanation: 'A opção `--add` (ou `-a`) insere um dispositivo de substituição em um array existente durante a operação.' },
  { id: 'lpic2-204-11', topicId: 5, question: 'Qual é o propósito dos snapshots LVM?', options: ['Criar backups permanentes em fita', 'Capturar instantaneamente o estado de um Logical Volume (Copy-on-Write) para backups consistentes', 'Acelerar a leitura do disco', 'Converter ext4 para xfs'], answer: 1, explanation: 'Snapshots rastreiam mudanças via CoW, permitindo fazer o backup de um estado fixo no tempo de um volume sem interromper o serviço.' },
  { id: 'lpic2-204-12', topicId: 5, question: 'Em um ambiente iSCSI, o que é o IQN?', options: ['Internal Query Network', 'iSCSI Qualified Name', 'Internet Quota Node', 'Initial Queue Number'], answer: 1, explanation: 'O iSCSI Qualified Name (IQN) é um identificador mundialmente exclusivo para iniciadores e alvos.' },
  { id: 'lpic2-204-13', topicId: 5, question: 'Qual opção do `hdparm` recupera ou define o timeout de spindown de um disco rígido?', options: ['-S', '-y', '-Z', '-B'], answer: 0, explanation: '`hdparm -S` define o tempo de espera antes de desligar os motores dos discos (spindown) para uma unidade IDE/SATA/SAS.' },
  { id: 'lpic2-204-14', topicId: 5, question: 'Qual arquivo armazena dinamicamente o status e detalhes dos arrays RAID de software do `mdadm`?', options: ['/etc/mdadm.conf', '/proc/mdstat', '/var/log/raid.log', '/sys/block/raid'], answer: 1, explanation: '`/proc/mdstat` fornece um resumo em tempo real dos arrays de software RAID do kernel e seu status de sincronização.' },
  { id: 'lpic2-204-15', topicId: 5, question: 'Qual componente LVM é criado diretamente em uma partição de disco bruta?', options: ['Volumes lógicos (LV)', 'Volume Group (VG)', 'Volume Físico (PV)', 'Volume Extent (VE)'], answer: 2, explanation: 'Um Volume Físico (PV) é a estrutura LVM básica criada diretamente em um disco ou partição.' },
// --- NOVO BATCH 2 (Tópicos 205-209) ---
  { id: 'lpic2-205-6', topicId: 6, question: 'Qual comando exibe a tabela de roteamento IP atual usando a suíte iproute2?', options: ['route -n', 'netstat -r', 'ip route show', 'ifconfig -r'], answer: 2, explanation: 'O comando `ip route show` é a forma moderna de visualizar a tabela de roteamento no Linux.' },
  { id: 'lpic2-205-7', topicId: 6, question: 'O que o utilitário `tracepath` faz?', options: ['Traça o caminho dos pacotes e descobre o MTU do caminho', 'Mede a largura de banda da rede', 'Configura interfaces de rede', 'Criptografa o tráfego de rede'], answer: 0, explanation: '`tracepath` rastreia o caminho para um destino de rede e tenta descobrir o Path MTU (Maximum Transmission Unit).' },
  { id: 'lpic2-205-8', topicId: 6, question: 'Qual arquivo é usado para configurar a ordem em que os serviços de nomes (como DNS, arquivos locais) são consultados?', options: ['/etc/resolv.conf', '/etc/hosts', '/etc/nsswitch.conf', '/etc/networks'], answer: 2, explanation: '`/etc/nsswitch.conf` define a ordem de prioridade para várias fontes de informações do sistema, incluindo a resolução de host.' },
  { id: 'lpic2-205-9', topicId: 6, question: 'Qual comando `ip` é usado para ativar uma interface de rede específica (ex: eth0)?', options: ['ip link set eth0 up', 'ip addr add eth0 up', 'ip interface start eth0', 'ifup eth0'], answer: 0, explanation: '`ip link set [interface] up` altera o estado administrativo da interface para "up".' },
  { id: 'lpic2-205-10', topicId: 6, question: 'Qual comando mostra estatísticas detalhadas de pacotes para todas as interfaces de rede?', options: ['ip -s link', 'netstat -i', 'ifconfig -v', 'Ambos (A e B)'], answer: 3, explanation: 'Tanto `ip -s link` quanto `netstat -i` fornecem estatísticas como pacotes recebidos, transmitidos e erros.' },
  { id: 'lpic2-205-11', topicId: 6, question: 'O que é o `NetworkManager`?', options: ['Um driver de placa de rede', 'Um daemon que gerencia conexões de rede de forma dinâmica e automática', 'Um firewall de rede', 'Um servidor DNS'], answer: 1, explanation: 'O NetworkManager tenta manter a conectividade de rede ativa e gerencia perfis de conexão via Wi-Fi, Ethernet e VPN.' },
  { id: 'lpic2-205-12', topicId: 6, question: 'Qual ferramenta de linha de comando é frequentemente usada com o NetworkManager?', options: ['nmcli', 'nmtui', 'Ambos (A e B)', 'netconfig'], answer: 2, explanation: '`nmcli` é a interface de linha de comando e `nmtui` é a interface baseada em texto (TUI) para o NetworkManager.' },
  { id: 'lpic2-205-13', topicId: 6, question: 'Qual sinalizador do `tcpdump` permite salvar a captura em um arquivo formatado para análise posterior no Wireshark?', options: ['-s', '-r', '-w', '-l'], answer: 2, explanation: 'O sinalizador `-w [arquivo]` salva os pacotes brutos (pcap) em um arquivo.' },
  { id: 'lpic2-205-14', topicId: 6, question: 'Como você adiciona permanentemente um servidor de nomes (DNS) no arquivo de configuração legada do sistema?', options: ['Editando /etc/hosts', 'Editando /etc/resolv.conf', 'Editando /etc/named.conf', 'Editando /etc/networks'], answer: 1, explanation: 'O arquivo `/etc/resolv.conf` lista os endereços IP dos servidores de nomes que o sistema deve consultar.' },
  { id: 'lpic2-205-15', topicId: 6, question: 'Qual comando exibe estatísticas detalhadas do protocolo TCP/UDP no sistema?', options: ['netstat -s', 'ss -s', 'Ambos (A e B)', 'ip route'], answer: 2, explanation: 'Tanto `netstat -s` quanto `ss -s` exibem um resumo resumido das estatísticas por protocolo.' },

  { id: 'lpic2-206-6', topicId: 7, question: 'Qual comando é usado para verificar a integridade de um arquivo baixado usando seu checksum MD5?', options: ['md5sum -check file', 'md5sum -c file.md5', 'verify-md5 file', 'check-file --md5'], answer: 1, explanation: '`md5sum -c` lê um arquivo contendo os checksums e os nomes dos arquivos e verifica se eles correspondem.' },
  { id: 'lpic2-206-7', topicId: 7, question: 'O que o comando `patch` faz?', options: ['Atualiza o kernel', 'Aplica mudanças em um arquivo fonte usando um arquivo de diff', 'Corrige erros de disco', 'Instala novos pacotes'], answer: 1, explanation: 'O comando `patch` pega um arquivo de diferenças (gerado pelo `diff`) e o aplica a um arquivo original para atualizá-lo.' },
  { id: 'lpic2-206-8', topicId: 7, question: 'Qual variável de ambiente geralmente armazena o caminho onde o `make` procura por bibliotecas durante a compilação?', options: ['PATH', 'LD_LIBRARY_PATH', 'LIBRARY_PATH', 'C_INCLUDE_PATH'], answer: 1, explanation: '`LD_LIBRARY_PATH` instrui o linkador dinâmico sobre onde procurar por bibliotecas compartilhadas.' },
  { id: 'lpic2-206-9', topicId: 7, question: 'Como você descompacta um arquivo .tar.bz2?', options: ['tar -xvf file.tar.bz2', 'tar -jxvf file.tar.bz2', 'tar -zxvf file.tar.bz2', 'bunzip2 file.tar.bz2'], answer: 1, explanation: 'A opção `-j` (ou --bzip2) é necessária para lidar com a compressão bzip2 em versões mais antigas do tar (embora o tar moderno frequentemente detecte automaticamente).' },
  { id: 'lpic2-206-10', topicId: 7, question: 'Qual é o propósito da ferramenta `ldd`?', options: ['Listar diretórios', 'Listar dependências de bibliotecas compartilhadas de um executável', 'Compilar código C', 'Depurar drivers de kernel'], answer: 1, explanation: '`ldd` imprime as bibliotecas compartilhadas exigidas por cada programa ou biblioteca compartilhada especificada na linha de comando.' },
  { id: 'lpic2-206-11', topicId: 7, question: 'Qual comando remove todos os arquivos objeto e binários criados por uma compilação anterior, preparando o diretório para uma nova compilação?', options: ['make install', 'make distclean', 'make clean', 'rm -rf *'], answer: 2, explanation: '`make clean` remove os arquivos gerados pelo `make` no diretório de construção.' },
  { id: 'lpic2-206-12', topicId: 7, question: 'Qual arquivo de configuração global é lido pelo `ldconfig` para determinar onde procurar por bibliotecas compartilhadas?', options: ['/etc/ld.so.conf', '/etc/libs.conf', '/etc/ld.library.path', '/etc/ld.so.cache'], answer: 0, explanation: '`/etc/ld.so.conf` contém uma lista de diretórios onde as bibliotecas compartilhadas são pesquisadas.' },
  { id: 'lpic2-206-13', topicId: 7, question: 'O que o sinalizador `-z` faz no `rsync`?', options: ['Exclui arquivos', 'Compacta os dados durante a transferência', 'Faz uma "dry run"', 'Preserva as permissões'], answer: 1, explanation: 'A opção `-z` (ou --compress) compacta os dados dos arquivos à medida que eles são enviados para reduzir o uso da largura de banda.' },
  { id: 'lpic2-206-14', topicId: 7, question: 'Qual ferramenta é usada para analisar os logs binários do systemd?', options: ['tail -f /var/log/syslog', 'journalctl', 'logread', 'systemview'], answer: 1, explanation: '`journalctl` é a ferramenta de linha de comando para consultar e exibir logs do `journald`.' },
  { id: 'lpic2-206-15', topicId: 7, question: 'Como você visualiza apenas os erros críticos no journal do systemd desde o último boot?', options: ['journalctl -b -p err', 'journalctl -u critical', 'cat /var/log/messages | grep error', 'journalctl --last --errors'], answer: 0, explanation: '`-b` limita ao boot atual e `-p err` filtra pela prioridade de erro (ou superior).' },

  { id: 'lpic2-207-6', topicId: 8, question: 'Qual tipo de registro DNS é usado para fornecer mapeamento reverso (IP para Nome de Host)?', options: ['A', 'CNAME', 'PTR', 'NS'], answer: 2, explanation: 'Registros Pointer (PTR) são usados em zonas de pesquisa reversa (in-addr.arpa) para mapear endereços IP a nomes de domínio.' },
  { id: 'lpic2-207-7', topicId: 8, question: 'O que o campo "Serial" em um arquivo de zona SOA (Start of Authority) indica?', options: ['O número de versão do software BIND', 'O número de série do hardware do servidor', 'O número da versão do arquivo de zona (usado por escravos para saber quando atualizar)', 'O tempo de vida dos registros'], answer: 2, explanation: 'Sempre que a zona é alterada, o Serial deve ser incrementado para que os servidores secundários (escravos) percebam a mudança e iniciem uma transferência de zona.' },
  { id: 'lpic2-207-8', topicId: 8, question: 'Qual ferramenta é usada para realizar consultas DNS básicas e avançadas no terminal?', options: ['ping', 'dig', 'whois', 'netstat'], answer: 1, explanation: '`dig` (Domain Information Groper) é o utilitário padrão para testar e solucionar problemas em servidores DNS.' },
  { id: 'lpic2-207-9', topicId: 8, question: 'Qual registro DNS define o servidor de nomes autoritativo para um domínio?', options: ['SOA', 'NS', 'MX', 'TXT'], answer: 1, explanation: 'Registros Name Server (NS) identificam os servidores DNS que são responsáveis por responder consultas sobre o domínio.' },
  { id: 'lpic2-207-10', topicId: 8, question: 'O que é uma "Transferência de Zona" (AXFR/IXFR)?', options: ['Mover um domínio para outra empresa', 'O processo de copiar dados de zona de um servidor DNS mestre para um escravo', 'Redirecionar tráfego web', 'Atualizar o cache do navegador'], answer: 1, explanation: 'Transferências de zona garantem que todos os servidores autoritativos para um domínio tenham os mesmos registros.' },
  { id: 'lpic2-207-11', topicId: 8, question: 'Como você recarrega as configurações do BIND e seus arquivos de zona sem reiniciar o serviço?', options: ['systemctl restart named', 'rndc reload', 'named-checkconf', 'killall -HUP named'], answer: 1, explanation: '`rndc` (Remote Name Daemon Control) permite administrar o servidor named em execução de forma segura.' },
  { id: 'lpic2-207-12', topicId: 8, question: 'Qual é o propósito da opção "recursion" no arquivo de configuração do BIND?', options: ['Permitir que o servidor resolva domínios fora de suas próprias zonas autoritativas', 'Aumentar a velocidade do boot', 'Ativar o DNSSEC', 'Bloquear consultas de spam'], answer: 0, explanation: 'Se a recursão estiver ativada, o servidor DNS buscará a resposta em outros servidores caso não a tenha localmente.' },
  { id: 'lpic2-207-13', topicId: 8, question: 'Em qual arquivo você configura o BIND para permitir que apenas determinadas redes façam transferências de zona?', options: ['/etc/hosts', 'named.conf (opção allow-transfer)', '/etc/resolv.conf', '/var/named/zones.allow'], answer: 1, explanation: 'A diretiva `allow-transfer` dentro do `named.conf` (global ou por zona) é vital para a segurança.' },
  { id: 'lpic2-207-14', topicId: 8, question: 'Qual registro DNS é usado para especificar o endereço IPv6 de um nome de host?', options: ['A', 'AAAA', 'CNAME', 'PTR'], answer: 1, explanation: 'Registros quad-A (AAAA) ligam um nome de host a um endereço IPv6 de 128 bits.' },
  { id: 'lpic2-207-15', topicId: 8, question: 'O que o comando `host -t MX google.com` faz?', options: ['Verifica a conexão com o Google', 'Lista os servidores de e-mail do Google', 'Mostra o endereço IP do Google', 'Exibe os servidores DNS do Google'], answer: 1, explanation: 'A opção `-t MX` solicita especificamente os registros de Mail Exchange para o domínio informado.' },

  { id: 'lpic2-208-6', topicId: 9, question: 'Qual arquivo de configuração do Apache é normalmente usado para definir módulos carregados e configurações globais no Debian/Ubuntu?', options: ['/etc/apache2/apache2.conf', '/etc/httpd/conf/httpd.conf', '/etc/apache2/httpd.conf', '/usr/local/apache/conf'], answer: 0, explanation: 'Em sistemas baseados em Debian, o arquivo mestre é o `apache2.conf`.' },
  { id: 'lpic2-208-7', topicId: 9, question: 'Como você habilita uma nova configuração de VirtualHost no Apache no Debian/Ubuntu?', options: ['Editando apache2.conf e reiniciando', 'Copiando o arquivo para /var/www/', 'Usando o comando a2ensite [nome_do_arquivo]', 'Apagando o link simbólico default'], answer: 2, explanation: '`a2ensite` cria um link simbólico de `sites-available` para `sites-enabled`.' },
  { id: 'lpic2-208-8', topicId: 9, question: 'Qual diretiva do Nginx define o diretório raiz onde os arquivos do site estão armazenados?', options: ['DocumentRoot', 'root', 'index', 'location'], answer: 1, explanation: 'No Nginx, usa-se a diretiva `root` dentro do bloco `server` ou `location`.' },
  { id: 'lpic2-208-9', topicId: 9, question: 'Qual é a função do comando `apachectl configtest`?', options: ['Inicia o servidor', 'Verifica erros de sintaxe nos arquivos de configuração do Apache', 'Testa a velocidade do site', 'Gera um certificado SSL'], answer: 1, explanation: 'Sempre deve-se testar a configuração antes de reiniciar o serviço para evitar indisponibilidade por erros de digitação.' },
  { id: 'lpic2-208-10', topicId: 9, question: 'Qual módulo do Apache é comumente usado para reescrever URLs de forma amigável ao usuário (SEO)?', options: ['mod_ssl', 'mod_rewrite', 'mod_proxy', 'mod_alias'], answer: 1, explanation: '`mod_rewrite` permite a manipulação dinâmica de URLs com base em regras de expressão regular.' },
  { id: 'lpic2-208-11', topicId: 9, question: 'O que é o "Proxy Reverso"?', options: ['Um firewall para o cliente', 'Um servidor que recebe requisições da internet e as encaminha para servidores internos', 'Uma VPN', 'Um servidor de banco de dados'], answer: 1, explanation: 'Inscrito na frente dos servidores de aplicação, ele oculta a topologia interna e pode prover cache e balanceamento.' },
  { id: 'lpic2-208-12', topicId: 9, question: 'No Nginx, qual bloco é usado para lidar com diferentes domínios no mesmo servidor?', options: ['server { ... }', 'vhost { ... }', 'site { ... }', 'domain { ... }'], answer: 0, explanation: 'Cada bloco `server` no Nginx define um servidor virtual.' },
  { id: 'lpic2-208-13', topicId: 9, question: 'Qual sinal você envia ao Nginx para que ele recarregue as configurações sem interromper as conexões ativas?', options: ['nginx -s reload', 'nginx -s stop', 'nginx -k reload', 'systemctl restart nginx'], answer: 0, explanation: '`-s reload` envia o sinal HUP ao processo mestre, que reinicia os processos workers com a nova configuração.' },
  { id: 'lpic2-208-14', topicId: 9, question: 'O que o Squid faz quando recebe uma requisição para uma URL que já está em seu cache local?', options: ['Descarta a requisição', 'Retorna o objeto direto do cache (Cache Hit) sem consultar a internet', 'Consulta a internet e atualiza o objeto obrigatoriamente', 'Bloqueia o acesso'], answer: 1, explanation: 'O "Cache Hit" economiza largura de banda e tempo de resposta para o usuário final.' },
  { id: 'lpic2-208-15', topicId: 9, question: 'Qual diretiva de log do Apache define o local e o formato dos logs de acesso?', options: ['ErrorLog', 'AccessLog', 'CustomLog', 'TransferLog'], answer: 2, explanation: '`CustomLog` define onde as requisições bem-sucedidas são registradas junto com seu formato.' },

  { id: 'lpic2-209-6', topicId: 10, question: 'Qual comando do Samba mostra quais usuários estão conectados e quais arquivos estão abertos no momento?', options: ['smbstatus', 'testparm', 'nmblookup', 'samba-tool'], answer: 0, explanation: '`smbstatus` fornece um resumo das sessões ativas e bloqueios de arquivos no servidor Samba.' },
  { id: 'lpic2-209-7', topicId: 10, question: 'Como você monta um compartilhamento NFS (/mnt/nfs) de um servidor remoto (192.168.1.10) manualmente?', options: ['mount -t nfs 192.168.1.10:/shared /mnt/nfs', 'mount --nfs 192.168.1.10 /mnt/nfs', 'net use /mount nfs', 'nfs-client connect 192.168.1.10'], answer: 0, explanation: 'A sintaxe padrão é `mount -t nfs [IP]:[caminho_remoto] [ponto_de_montagem].`' },
  { id: 'lpic2-209-8', topicId: 10, question: 'Qual utilitário verifica a sintaxe do arquivo de configuração smb.conf em busca de erros?', options: ['smb-check', 'testparm', 'samba-lint', 'check-samba'], answer: 1, explanation: 'Sempre use o `testparm` após editar o smb.conf para validar as opções e parâmetros.' },
  { id: 'lpic2-209-9', topicId: 10, question: 'O que a opção `browsable = yes` no Samba faz?', options: ['Permite que o compartilhamento apareça na rede Windows (Network Discovery)', 'Permite navegar na internet pelo Samba', 'Permite acesso sem senha', 'Permite escrita no diretório'], answer: 0, explanation: 'Se definido como "no", o compartilhamento fica oculto e o usuário precisa digitar o caminho exato para acessá-lo.' },
  { id: 'lpic2-209-10', topicId: 10, question: 'Qual daemon do Samba lida com a resolução de nomes NetBIOS e o anúncio na rede?', options: ['smbd', 'nmbd', 'winbindd', 'samba-d'], answer: 1, explanation: 'O `nmbd` é responsável por tornar o servidor visível na rede Windows e gerenciar grupos de trabalho.' },
  { id: 'lpic2-209-11', topicId: 10, question: 'Como você remove o mapeamento de um usuário do banco de dados de senhas do Samba?', options: ['smbpasswd -r', 'smbpasswd -x', 'smb-del-user', 'userdel'], answer: 1, explanation: 'A opção `-x` exclui o usuário do arquivo passdb.tdb do Samba.' },
  { id: 'lpic2-209-12', topicId: 10, question: 'No NFS, qual opção no /etc/exports mapeia todas as requisições de root do cliente para um usuário anônimo (normalmente nobody)?', options: ['no_root_squash', 'root_squash', 'all_squash', 'anon_root'], answer: 1, explanation: 'Por segurança, o NFS por padrão ativa o `root_squash` para impedir que o root do cliente tenha privilégios de root no servidor.' },
  { id: 'lpic2-209-13', topicId: 10, question: 'Qual é o propósito do daemon `rpcbind` (antigo portmap) para o NFS?', options: ['Criptografar os dados', 'Mapear chamadas de procedimento remoto (RPC) para as portas de rede corretas', 'Fornecer senhas', 'Gerenciar o cache de disco'], answer: 1, explanation: 'O NFS depende do RPC, e o `rpcbind` informa ao cliente em qual porta o serviço NFS está escutando.' },
  { id: 'lpic2-209-14', topicId: 10, question: 'Qual comando exibe os compartilhamentos NFS disponíveis em um servidor remoto?', options: ['showmount -e [IP_do_Servidor]', 'nfs-list [IP_do_Servidor]', 'ls /net/[IP_do_Servidor]', 'cat /proc/nfs'], answer: 0, explanation: '`showmount -e` (export list) é a ferramenta para descobrir o que um servidor NFS está exportando.' },
  { id: 'lpic2-209-15', topicId: 10, question: 'Qual parâmetro no smb.conf define o grupo de trabalho (Workgroup) ou o nome do domínio NT?', options: ['domain-name', 'workgroup', 'netbios-name', 'server-role'], answer: 1, explanation: 'A diretiva `workgroup` na seção [global] define o grupo ao qual o servidor pertence.' },
  { id: 'lpic2-209-16', topicId: 10, question: 'Ao revisar o arquivo `/etc/exports`, o que o parâmetro `no_root_squash` faz?', options: ['Impede totalmente o acesso do root', 'Permite que o usuário root remoto mantenha privilégios de root no diretório exportado', 'Compacta arquivos acessados pelo root', 'Mapeia o root para o usuário nobody'], answer: 1, explanation: 'Normalmente, o NFS anula (squash) as solicitações de root para um UID anônimo. O `no_root_squash` anula isso, apresentando um risco de segurança severo se usado sem cuidado.' },
// --- NOVO BATCH 3 (Tópicos 210-212) ---
  { id: 'lpic2-210-6', topicId: 11, question: 'Na configuração do servidor DHCP ISC (`dhcpd.conf`), qual parâmetro define a duração padrão de um IP alugado a um cliente se ele não solicitar um tempo específico?', options: ['max-lease-time', 'default-lease-time', 'lease-duration', 'expire-time'], answer: 1, explanation: '`default-lease-time` é o tempo de alocação padrão em segundos.' },
  { id: 'lpic2-210-7', topicId: 11, question: 'Qual daemon do DHCP ISC cria o log centralizado de IPs alugados, armazenando o estado entre reinicializações?', options: ['/etc/dhcp/dhcpd.conf', '/var/lib/dhclient/dhclient.leases', '/var/lib/dhcp/dhcpd.leases', '/var/log/dhcpd.log'], answer: 2, explanation: 'O arquivo `dhcpd.leases` serve como banco de dados para rastrear alocações ativas.' },
  { id: 'lpic2-210-8', topicId: 11, question: 'Quais são os quatro grupos de gerenciamento dentro de um arquivo de configuração de módulo PAM?', options: ['allow, deny, warn, critical', 'auth, account, password, session', 'user, group, other, root', 'login, shell, network, local'], answer: 1, explanation: 'O PAM organiza regras em auth (identidade), account (validade), password (atualização de credenciais) e session (configuração/encerramento).' },
  { id: 'lpic2-210-9', topicId: 11, question: 'Em uma pilha PAM, o que acontece se um módulo marcado como `requisite` falhar?', options: ['A pilha retorna imediatamente falha sem executar módulos adicionais', 'A falha é registrada, mas o próximo módulo é testado', 'O usuário é enviado para uma shell limitada', 'O sistema solicita um CAPTCHA ao usuário'], answer: 0, explanation: 'Diferente de `required`, o `requisite` causa falha instantânea, evitando processamento adicional.' },
  { id: 'lpic2-210-10', topicId: 11, question: 'Por padrão, em qual porta TCP o LDAP não criptografado opera?', options: ['110', '389', '636', '3306'], answer: 1, explanation: 'O LDAP comunica-se pela porta TCP 389, enquanto o LDAPS (LDAP sobre SSL) usa a porta 636.' },
  { id: 'lpic2-210-11', topicId: 11, question: 'Qual daemon é o motor central da suíte de servidor OpenLDAP?', options: ['ldap_agent', 'named', 'slapd', 'sssd'], answer: 2, explanation: '`slapd` significa Stand-Alone LDAP Daemon.' },
  { id: 'lpic2-210-12', topicId: 11, question: 'Qual utilitário de linha de comando consulta um diretório LDAP usando filtros?', options: ['ldapquery', 'ldapsearch', 'ldaplookup', 'ldapfind'], answer: 1, explanation: '`ldapsearch` abre uma conexão com um servidor LDAP, faz o bind e realiza uma busca usando um filtro.' },
  { id: 'lpic2-210-13', topicId: 11, question: 'Qual daemon moderno é usado intensamente no Linux para cache de credenciais e gerenciamento de conexões com diretórios centrais como LDAP ou Active Directory?', options: ['nscd', 'sssd', 'pam_unix', 'winbind'], answer: 1, explanation: 'O System Security Services Daemon (SSSD) integra o sistema com diretórios remotos e fornece cache offline.' },
  { id: 'lpic2-210-14', topicId: 11, question: 'No OpenVPN, para rotear todo o tráfego de internet do cliente através da VPN, qual diretiva específica deve ser enviada ao cliente?', options: ['push "route 0.0.0.0 0.0.0.0"', 'push "redirect-gateway def1"', 'push "default-route"', 'route-all'], answer: 1, explanation: '`redirect-gateway def1` modifica a tabela de roteamento padrão do cliente para apontar para o túnel VPN.' },
  { id: 'lpic2-210-15', topicId: 11, question: 'Qual comando força um cliente Linux a liberar manualmente seu endereço IP alugado via DHCP e interromper o daemon?', options: ['dhclient -x', 'dhclient -r', 'ifdown eth0', 'ip addr flush'], answer: 1, explanation: '`dhclient -r` libera explicitamente o aluguel atual para o servidor e para o daemon cliente.' },
  { id: 'lpic2-210-16', topicId: 11, question: 'Qual é o sufixo/extensão padrão para o arquivo da autoridade certificadora usado para autenticar clientes OpenVPN?', options: ['.key', '.crt', '.csr', '.ca'], answer: 1, explanation: 'Certificados (chaves públicas) geralmente usam a extensão `.crt` ou `.pem`.' },

  { id: 'lpic2-211-6', topicId: 12, question: 'Qual comando exibe o conteúdo atual da fila de mensagens do Postfix?', options: ['mailq', 'postqueue -p', 'Ambos (A e B)', 'qstat'], answer: 2, explanation: '`mailq` geralmente é um link simbólico para `postqueue -p`, que imprime a fila.' },
  { id: 'lpic2-211-7', topicId: 12, question: 'O que o comando do Postfix `postsuper -d ALL` faz?', options: ['Remove todos os e-mails da fila de mensagens', 'Baixa todos os e-mails do MTA', 'Implanta uma nova configuração do supervisor', 'Desabilita o servidor de e-mail'], answer: 0, explanation: '`postsuper` gerencia a fila do Postfix; `-d ALL` deleta permanentemente todas as mensagens na fila.' },
  { id: 'lpic2-211-8', topicId: 12, question: 'Qual parâmetro no `main.cf` define quais nomes de domínio o Postfix considera a si mesmo como destino final?', options: ['myhostname', 'mynetworks', 'mydestination', 'relay_domains'], answer: 2, explanation: 'E-mails endereçados a domínios listados em `mydestination` são entregues localmente.' },
  { id: 'lpic2-211-9', topicId: 12, question: 'Se você deseja que o Postfix rejeite e-mails de endereços IP de spammers conhecidos globalmente, qual diretiva você configuraria para usar DNS Blocklists (DNSBL)?', options: ['smtpd_recipient_restrictions', 'smtpd_client_restrictions', 'header_checks', 'virtual_alias_maps'], answer: 1, explanation: '`smtpd_client_restrictions = reject_rbl_client zen.spamhaus.org` avalia o IP de conexão antes de qualquer transação.' },
  { id: 'lpic2-211-10', topicId: 12, question: 'Qual porta é historicamente reservada para o protocolo POP3 (não criptografado)?', options: ['25', '110', '143', '993'], answer: 1, explanation: 'O Post Office Protocol versão 3 opera na porta TCP 110.' },
  { id: 'lpic2-211-11', topicId: 12, question: 'No Dovecot, qual é a porta padrão para IMAPS (IMAP Seguro sobre SSL/TLS)?', options: ['143', '465', '587', '993'], answer: 3, explanation: 'O IMAPS utiliza TLS implicitamente seguro na porta TCP 993.' },
  { id: 'lpic2-211-12', topicId: 12, question: 'Qual linguagem de script MDA é considerada a alternativa moderna e padronizada ao Procmail, projetada especificamente para se integrar perfeitamente ao Dovecot?', options: ['Bash', 'Python', 'Sieve', 'Perl'], answer: 2, explanation: 'Sieve é uma linguagem de script altamente segura e padronizada para filtrar e-mails no nível MTA/MDA.' },
  { id: 'lpic2-211-13', topicId: 12, question: 'Onde as receitas do Procmail são tipicamente definidas por usuário?', options: ['/etc/procmail.conf', '~/.procmailrc', '/var/spool/mail/recipes', '~/.mailfilter'], answer: 1, explanation: 'Os usuários criam receitas pessoais de roteamento de e-mail em `.procmailrc` em seus diretórios home.' },
  { id: 'lpic2-211-14', topicId: 12, question: 'Qual é a função do parâmetro `mynetworks` no Postfix?', options: ['Bloqueia spam daquelas redes', 'Define a lista de redes locais autorizadas a retransmitir e-mails através do servidor para domínios externos', 'Mapeia endereços IP locais', 'Define as interfaces IP em que o Postfix escuta'], answer: 1, explanation: 'Clientes vindos de IPs que coincidem com `mynetworks` têm permissão implícita para retransmitir e-mail.' },
  { id: 'lpic2-211-15', topicId: 12, question: 'Qual comando força o Postfix a tentar imediatamente a entrega de todas as mensagens adiadas na fila?', options: ['postsuper -r', 'postfix flush', 'postqueue -f', 'mailq -f'], answer: 2, explanation: '`postqueue -f` percorre a fila de e-mails e tenta um envio imediato.' },
  { id: 'lpic2-211-16', topicId: 12, question: 'O que a diretiva `virtual_alias_maps` do Postfix configura?', options: ['Mapeia domínios virtuais para endereços IP físicos', 'Encaminha e-mails de um endereço específico (ex: info@dominio.com) para caixas de correio reais de destino', 'Mapeia endereços IP externos para servidores internos', 'Cria respostas de férias automáticas'], answer: 1, explanation: 'Aliases virtuais reescrevem endereços de destinatários, comumente usados para encaminhamento.' },

  { id: 'lpic2-212-6', topicId: 13, question: 'No iptables, qual opção anexa uma regra ao final de uma corrente (chain)?', options: ['-I', '-A', '-D', '-R'], answer: 1, explanation: '`-A` significa Append (Anexar), enquanto `-I` insere uma regra no topo (ou em um número de linha específico).' },
  { id: 'lpic2-212-7', topicId: 13, question: 'Qual comando lista todas as regras de iptables na tabela NAT?', options: ['iptables -L', 'iptables -t nat -L', 'iptables -nL --table nat', 'iptables --list nat'], answer: 1, explanation: '`-t nat` especifica a tabela alvo, e `-L` lista as regras.' },
  { id: 'lpic2-212-8', topicId: 13, question: 'Qual corrente (chain) de filtro no iptables lida com pacotes cujo destino final é o próprio servidor?', options: ['FORWARD', 'OUTPUT', 'INPUT', 'PREROUTING'], answer: 2, explanation: 'A corrente `INPUT` processa pacotes recebidos endereçados a sockets locais.' },
  { id: 'lpic2-212-9', topicId: 13, question: 'No `iptables`, o que o alvo `MASQUERADE` faz?', options: ['Esconde os dados do pacote', 'Traduz o IP de origem de pacotes de saída dinamicamente para o IP da interface de saída', 'Bloqueia hackers conhecidos', 'Cria um túnel VPN'], answer: 1, explanation: 'Masquerading é SNAT dinâmico, muito usado em roteadores com IPs públicos dinâmicos.' },
  { id: 'lpic2-212-10', topicId: 13, question: 'Com o Nmap, o que a flag `-sS` especifica?', options: ['Varredura UDP', 'Varredura TCP SYN (Stealth)', 'Varredura TCP Connect', 'Varredura FIN'], answer: 1, explanation: 'A varredura SYN realiza um handshake TCP meio aberto altamente eficiente para mapear portas.' },
  { id: 'lpic2-212-11', topicId: 13, question: 'Qual argumento de linha de comando diz ao Nmap para tentar identificar o Sistema Operacional do host remoto?', options: ['-O', '-sV', '-A', 'Ambos (A e C)'], answer: 3, explanation: '`-O` ativa especificamente a detecção de SO. `-A` (Agressivo) ativa a detecção de SO junto com varredura de versão e scripts.' },
  { id: 'lpic2-212-12', topicId: 13, question: 'No Fail2ban, qual arquivo os administradores devem usar para customizar configurações de "jail" para evitar que atualizações de pacotes as sobrescrevam?', options: ['jail.conf', 'fail2ban.conf', 'jail.local', 'iptables.local'], answer: 2, explanation: '`jail.local` sobrescreve o `jail.conf`, servindo como repositório seguro para modificações locais.' },
  { id: 'lpic2-212-13', topicId: 13, question: 'Qual variável no Fail2ban define a duração (em segundos) que um IP infrator permanece bloqueado?', options: ['blocktime', 'findtime', 'maxretry', 'bantime'], answer: 3, explanation: '`bantime` define quanto tempo a regra de DROP no iptables permanece ativa.' },
  { id: 'lpic2-212-14', topicId: 13, question: 'Qual é o framework fundamental do kernel em que o iptables se baseia para interceptar a pilha de rede?', options: ['BPF', 'Netfilter', 'TCP Wrapper', 'AppArmor'], answer: 1, explanation: 'O Netfilter fornece os ganchos (hooks) no kernel Linux que permitem ao iptables/nftables interceptar e manipular pacotes.' },
  { id: 'lpic2-212-15', topicId: 13, question: 'Qual comando salva permanentemente as regras do iptables para a saída padrão na maioria das distribuições para scripts de backup?', options: ['iptables-save', 'iptables-backup', 'iptables -S', 'service iptables save'], answer: 0, explanation: '`iptables-save` exporta as regras em um formato legível por máquina (que pode ser restaurado via `iptables-restore`).' },
  { id: 'lpic2-212-16', topicId: 13, question: 'O que é um Teste de Vulnerabilidade de Rede (NVT) no contexto do OpenVAS/Greenbone?', options: ['Um sniffer de pacotes', 'Um script de plugin que fornece a lógica para detectar uma vulnerabilidade específica em um host remoto', 'Uma técnica de escaneamento de portas', 'Uma regra de detecção de intrusão'], answer: 1, explanation: 'NVTs são essencialmente os scripts de assinatura executados pelo OpenVAS para confirmar se um alvo é vulnerável.' },
  { id: 'lpic2-212-17', topicId: 13, question: 'Qual comando limpa (deleta) todas as regras na tabela de iptables selecionada no momento?', options: ['iptables -X', 'iptables -Z', 'iptables -F', 'iptables -R'], answer: 2, explanation: '`-F` (Flush) deleta instantaneamente todas as regras de todas as correntes (ou de uma corrente específica).' },
];
